import { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';
import './App.css';
import './animations.css';
import './admin.css';
import { getContent, loadDynamicContent } from './contentManager';

// Import pages
import Home from './pages/Home';
import Services from './pages/Services';
import Careers from './pages/Careers';
import Partners from './pages/Partners';
import Contact from './pages/Contact';
import JobApplication from './pages/JobApplication';
import AdminLogin from './pages/AdminLogin';
import AdminDashboard from './pages/AdminDashboard';

// Protected Route Component
function ProtectedRoute({ children }) {
  const isAuthenticated = localStorage.getItem('adminAuth') === 'true';
  return isAuthenticated ? children : <Navigate to="/admin/login" />;
}

function AppContent() {
  const [language, setLanguage] = useState('en');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [dynamicContent, setDynamicContent] = useState({});
  const [contentLoading, setContentLoading] = useState(true);
  const location = useLocation();

  // Check if on admin pages
  const isAdminPage = location.pathname.startsWith('/admin');

  // Load dynamic content from Supabase
  useEffect(() => {
    const loadContent = async () => {
      try {
        setContentLoading(true);
        console.log('Loading dynamic content from Supabase...');
        
        // Add timeout to prevent infinite loading
        const timeoutPromise = new Promise((_, reject) => 
          setTimeout(() => reject(new Error('Loading timeout')), 10000)
        );
        
        const content = await Promise.race([
          loadDynamicContent(),
          timeoutPromise
        ]);
        
        console.log('Dynamic content loaded:', content);
        setDynamicContent(content);
      } catch (error) {
        console.error('Error loading content:', error);
        // Set empty content as fallback
        setDynamicContent({
          careers: [],
          services: [],
          partners: [],
          aboutInfo: {},
          heroContent: {}
        });
      } finally {
        setContentLoading(false);
        console.log('Content loading completed');
      }
    };

    loadContent();
  }, []);

  // Smooth scroll animation observer
  useEffect(() => {
    if (isAdminPage) return;
    
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('visible');
            observer.unobserve(entry.target);
          }
        });
      },
      {
        threshold: 0.15,
        rootMargin: '0px'
      }
    );

    const animatedElements = document.querySelectorAll('.scroll-animate');
    animatedElements.forEach((el) => observer.observe(el));

    return () => observer.disconnect();
  }, [location, isAdminPage]);

  // Close mobile menu when route changes
  useEffect(() => {
    setIsMobileMenuOpen(false);
    window.scrollTo(0, 0);
  }, [location.pathname]);

  const handleLanguageToggle = () => {
    setLanguage(language === 'ar' ? 'en' : 'ar');
  };

  const handleLogin = () => {
    // Login handler
  };

